sys_script_client.script:
function onLoad() {
    var gr = new GlideRecord('incident');
    gr.addQuery('cmdb_ci.asset_tag', g_form.getValue('asset_tag'));
	gr.addQuery('state', 'NOT IN', '6,7,8'); 
	gr.addQuery('category', 'ev_Box'); 
    gr.query();

    if (gr.next()) {
        if (g_form.getValue('operational_status') == 2 || g_form.getValue('operational_status') == 3) {
            //Set the Incident referance in the field controled visibility in the UI Policy 'EV Incident Investigation'
            g_form.setValue('u_investigation', gr.sys_id);

            //Set the operational state to read only so it will no be changed by mistake
            g_form.setReadOnly('operational_status', true);
            g_form.showFieldMsg('operational_status', 'Isuses with the device detected, currently cannot change state.', 'info');
        }
    } else {
        g_form.setReadOnly('operational_status', false);
    }
}
